    const fiveScores = new Map([
      ["1", 0.1], ["2", 0.1], ["3", 0.1], ["4", 0.1], ["5", 0.1],
    ]);
    expect(formatScoredMessages(five, fiveScores)).toContain("5 zpráv");
  });
});

